/* Client-side search using search-index.json generated by Jekyll */
(function () {
  'use strict';

  var input   = document.getElementById('search-input');
  var results = document.getElementById('search-results');
  if (!input || !results) return;

  var index = null;

  // Lazy-load search index on first focus
  input.addEventListener('focus', function loadIndex() {
    if (index !== null) return;
    var base = document.querySelector('meta[name="baseurl"]');
    var baseurl = base ? base.getAttribute('content') : '';
    fetch(baseurl + '/search-index.json')
      .then(function (r) { return r.json(); })
      .then(function (data) { index = data; })
      .catch(function () { index = []; });
    input.removeEventListener('focus', loadIndex);
  }, { once: true });

  input.addEventListener('input', function () {
    var q = input.value.trim().toLowerCase();
    results.innerHTML = '';
    if (!q || !index || q.length < 2) { results.hidden = true; return; }

    var matches = index.filter(function (item) {
      return (item.title + ' ' + item.content).toLowerCase().indexOf(q) !== -1;
    }).slice(0, 10);

    if (matches.length === 0) { results.hidden = true; return; }

    matches.forEach(function (item) {
      var li = document.createElement('li');
      var a  = document.createElement('a');
      a.href = item.url;
      a.textContent = item.title;
      li.appendChild(a);
      results.appendChild(li);
    });
    results.hidden = false;
  });

  // Close when clicking outside
  document.addEventListener('click', function (e) {
    if (!results.contains(e.target) && e.target !== input) {
      results.hidden = true;
    }
  });
})();
